#include <cstdio>
int main() {
    // System: x1 - x2 + 3x3 = 2 ; 3x1 - 3x2 + x3 = -1 ; x1 + x2 = 3
    // Gaussian elimination with partial pivoting (swap E2/E3), then back-substitute.
    double x3 = -7.0 / -8.0;
    double x2 = (1.0 - (-3.0) * x3) / 2.0;
    double x1 = 2.0 + x2 - 3.0 * x3;
    printf("x1=%.4f x2=%.4f x3=%.4f\n", x1, x2, x3);
    return 0;
}
